INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (6, 'Unicare Clinic Ubud', 'unicare-clinic-ubud', 'Located in the cultural heart of Bali, Unicare Clinic Ubud serves as your trusted medical partner while exploring the uplands. We provide comprehensive healthcare services specifically tailored for international travelers, ranging from general doctor consultations and wound care to rapid treatment for common travel-related illnesses like Bali Belly. Our facility is staffed by professional English-speaking medical personnel who prioritize hygiene and patient safety in every procedure. To ensure a hassle-free experience, we also offer full assistance with medical reporting for travel insurance claims, allowing you to enjoy the serenity of Ubud with complete peace of mind.', 'Ubud', 'Indonesia', '', 0, 'https://daydreamhub.com/wp-content/uploads/2026/01/Medical-Wellness-Program-Bali-Medical-Clinic-Services-List.jpg', '["personal_time"]', '[]', 'Private Room', 1);
