INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (48, 'DAMAC Maison Cour Jardin/ One Bedroom Suite', 'damac-maison-cour-jardin-one-bedroom-suite', 'Located in the heart of Business Bay, DAMAC Maison Cour Jardin offers luxurious apartments with an Arabesque décor and panoramic views of Downtown Dubai. Only a 5-minute drive from the Business Bay metro station , it is within walking distance to Bay Avenue with its many shops and restaurants. The Cour Jardin offers high-speed complimentary WiFi in all areas, an outdoor infinity pool and a state-of-the-art fitness center.
