INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (51, 'Act One Act Two/ 3Bedroom', 'act-one-act-two-3bedroom', 'Act One | Act Two brings a new vision of luxury to The Opera District renowned for its culture and cosmopolitanism. The two-tower complex is comprised of one, two and three-bedroom premium apartments inspired by the iconic Dubai Fountain. The dynamic façades of these towering masterpieces mark the gateway to the world’s most notable skyscraper, Burj Khalifa – and a door to everything the iconic Downtown Dubai has to offer.
