INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (60, 'The  Address Opera Tower 1 / 2 Bedroom Apartment', 'the-address-opera-tower-1-2-bedroom-apartment', 'Downtown – Address Residences Opera T1 1603 offers a great location, putting you within a 15-minute walk of Dubai Mall and Burj Khalifa. Other highlights include a fitness centre and a garden. The property is only a short walk to public transportation: Burj Khalifa – Dubai Mall Station is 11 minutes away.', 'Dubai', 'UAE', '', 0, 'https://daydreamhub.com/wp-content/uploads/2025/08/Bedroom-5.jpg', '["daycation","for_couple"]', '["Elevator in Building","Gym","Laundry Service","Parking on Premises","Pool","Air Conditioner (Cooling)","Air Conditioner (Heating)","Bathtub","Coffee maker","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Kitchen","Refrigerator","Shampoo","Shower","TEL","Toothbrush","Towels","TV"]', 'Apartment', 1);
