INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (116, 'Taarifa Suites / Two-Bedroom Apartment', 'taarifa-suites-two-bedroom-apartment', 'The open concept of 2 Bedroom Apartment serviced apartments makes it the ideal choice for business travelers, couples, and smaller families looking to relocate. Even with a cozier area of the room, it still features a fully equipped kitchen and living room. Taarifa Suites studios are built to give you all the space you need for a comfortable stay while being able to host at your leisure.', 'Nairobi', 'Kenya', '', 0, 'https://daydreamhub.com/wp-content/uploads/2025/04/Taarifa-111-2br.jpg', '["daycation","personal_time"]', '["Elevator in Building","Gym","Laundry Service","Luggage Storage","Parking on Premises","Pool","Sauna","Air Conditioner (Cooling)","Air Conditioner (Heating)","Bathtub","Desk/Workspace","Electric pot","Free Wi-Fi","Kitchen","Refrigerator","Shampoo","Shower","TEL","Toothbrush","Towels","TV"]', 'Apartment', 1);
