INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (160, 'Asmara Urban Resort and Lifestyle Village / Deluxe King Panorama', 'asmara-urban-resort-and-lifestyle-village-deluxe-king-panorama', 'Distinctly named because of its panoramic view of the whole resort, the room provides an air of relaxed elegance and beautiful interiors, highlighting the Palmera collection of our sister furniture company (atelier-a). Its use of coconut bark highlights this room’s interpretation of tropical concepts. It was made with care to cater to our PWD and senior guests as well. This room allows them to enjoy and relax easily, surrounded by nature and the structural beauty of the Asmara Lifestyle Hotel and Asmara Urban Resort.', 'Cebu City', 'Philippines', '', 0, 'https://daydreamhub.com/wp-content/uploads/2025/02/スクリーンショット-2025-02-27-225744.jpg', '["for_couple"]', '["Bar / Restaurant","Laundry Service","Massage","Parking on Premises","Pool","Sauna","Wheelchair Accessible","Coffee maker","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Refrigerator","Shampoo","Shower","Toothbrush","Towels","TV"]', 'Hotel', 1);
