INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (161, 'Central Inn Souq Waqif/Suite Room', 'central-inn-souq-waqif-suite-room', 'At Central Inn Souq Waqif, enjoy a rare combination of contemporary elegance and homely touch with our artistic Suite Rooms. Enjoy the rich, warm tones of modern furniture, tableware, and artwork whilst taking in the expansive views offered by every room of this homely hotel. All suites are fully equipped with a kitchenette, dining area, and seating nooks for you to relax in. The rooms have been designed with your comfort in mind, offering everything you need for a comfortable stay. Our luxury suites offer guests every comfort they could wish for.', 'Doha', 'Qatar', '', 0, 'https://daydreamhub.com/wp-content/uploads/2025/03/Entrance.copy_.jpg', '["daycation","for_couple","for_work","luxury","personal_time","transit_use"]', '["Bar / Restaurant","Elevator in Building","Gym","Laundry Service","Luggage Storage","Pool","Air Conditioner (Cooling)","Electric pot","Free Wi-Fi","Hair Dryer","Shampoo","Shower","Toothbrush","Towels","TV"]', 'Hotel', 1);
