INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (164, 'Central Inn Souq Waqif/Standard room', 'central-inn-souq-waqif-standard-room', 'We put together all the comforts of a home and ensure that you have a great time in our hotel rooms. Our standard rooms are completely furnished with artfully designed furniture including beds, workstations, and modern amenities. The spacious rooms come with a flat-screen television and a comfortable sitting area. The rooms also entitle you to our in-house restaurants where you can enjoy devouring delectable cuisines from across the globe.', 'Doha', 'Qatar', '', 0, 'https://daydreamhub.com/wp-content/uploads/2025/03/Entrance.copy_.jpg', '["daycation","for_couple","for_work","luxury","personal_time","transit_use"]', '["Bar / Restaurant","Elevator in Building","Gym","Laundry Service","Luggage Storage","Pool","Air Conditioner (Cooling)","Electric pot","Free Wi-Fi","Hair Dryer","Shampoo","Shower","Toothbrush","Towels","TV"]', 'Hotel', 1);
