INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (183, 'Old Town Quito Suites / “High Ceilings” Suite', 'old-town-quito-suites-high-ceilings-suite', 'In the historic centre of Quito, at “Old Town Quito Suites – High Ceilings-suite” you’ll be captivated by the soaring ceilings in the living room that define its charm. As part of the best boutique hotel experience at this Hotel, every detail of this suite, from the luxurious high curtains to the old beams and solid parquet flooring, transports you to a bygone era. The elegant marble bathroom and spacious walk-in closet add a touch of modern luxury, making this one-bedroom apartment the perfect blend of history and comfort.. Free wifi is offered throughout the property, and private parking is available on site.', 'Pichincha', 'Ecuador', '', 2, 'https://daydreamhub.com/wp-content/uploads/2025/02/スクリーンショット-2025-02-21-215036.jpg', '["for_couple"]', '["Fax","Laundry Service","Luggage Storage","Massage","Parking on Premises","Wheelchair Accessible","Coffee maker","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Kitchen","Night wear","Refrigerator","Shampoo","Shower","Toothbrush","Towels","TV"]', 'Hotel', 1);
