INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (192, 'Springfield House B&B – Deluxe Double Room', 'springfield-house-bb-deluxe-double-room', 'Our Cellar Room offers a unique and charming stay, featuring a private entrance from the car park and self check-in for maximum convenience. Inside, you’ll find a luxurious whirlpool bath, a well-appointed work desk, a modern en-suite shower room with a heated towel rail, a hairdryer, tea/coffee making facilities, a smart TV, and complimentary Wi-Fi. Please note that while the Cellar Room provides ground-level accommodation, there are stairs at the entrance.', 'Birmingham', 'UK', '', 0, 'https://daydreamhub.com/wp-content/uploads/2025/01/498245047.jpg', '["early_check-in","for_couple","for_work","personal_time","transit_use"]', '["Luggage Storage","Parking on Premises","Bathtub","Coffee maker","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Shampoo","Shower","Toothbrush","Towels","TV"]', 'B&B', 1);
