INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (196, 'Flixses Suites at Platinum KLCC / Deluxe King Suite', 'flixses-suites-at-platinum-klcc-deluxe-king-suite', 'At the apartment complex, the units are equipped with air conditioning, a seating area, a flat-screen TV with streaming services, a kitchenette, a dining area, and a private bathroom with slippers, a walk-in shower, and a hair dryer. An oven, a microwave, and fridge are also featured, as well as a kettle.', 'Kuala Lumpur', 'Malaysia', '', 2, 'https://daydreamhub.com/wp-content/uploads/2025/02/585956666.jpg', '["for_couple","for_work","luxury","personal_time"]', '["Bar / Restaurant","Gym","Parking on Premises","Pool","Air Conditioner (Cooling)","Bathtub","Electric pot","Free Wi-Fi","Hair Dryer","Kitchen","Refrigerator","Shampoo","Shower","Towels","TV"]', 'Hotel', 1);
