INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (199, 'EKC Homestay Cummer', 'ekc-homestay-cummer', 'EKC Homestay Cummer provides a comfortable and affordable living space for international students and workers. This shared house features a communal kitchen, shared bathrooms and toilets, and free internet, making it an ideal choice for those seeking a convenient and budget-friendly accommodation. Located in a welcoming neighborhood, our homestay offers a friendly, community atmosphere where residents can enjoy both privacy and connection. Whether you’re here for work or study, you’ll find a home-like environment that meets your needs.', 'Ontario', 'Canada', '', 0, 'https://daydreamhub.com/wp-content/uploads/2025/02/Cummer-outside.jpeg', '["daycation","early_check-in","transit_use"]', '["Air Conditioner (Cooling)","Air Conditioner (Heating)","Desk/Workspace","Free Wi-Fi","Kitchen","Refrigerator"]', 'Private Room', 1);
