INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (210, 'Deluxe Room Twin Bed', 'deluxe-room-twin-bed', 'The hot tub is the standout feature of this double room. Featuring free toiletries and bathrobes, this double room includes a private bathroom with a walk-in shower, a bath and a hairdryer. The spacious air-conditioned double room features a flat-screen TV with cable channels, a minibar, a seating area, a wardrobe as well as city views. The unit has 1 bed.', 'Doha', 'Qatar', '', 0, 'https://daydreamhub.com/wp-content/uploads/2024/12/10-Deluxe-Twin-Room.jpg', '["transit_use"]', '["Bar / Restaurant","Currency Exchange","Elevator in Building","Gym","Laundry Service","Luggage Storage","Massage","Parking on Premises","Pool","Sauna","Wheelchair Accessible","Air Conditioner (Cooling)","Air Conditioner (Heating)","Bathtub","Coffee maker","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Night wear","Projector(s)","Shampoo","Shower","TEL","Toothbrush","Towels","TV"]', 'Hotel', 1);
