INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (238, 'Shota @Rustaveli Boutique Hotel / Superior Double Room', 'shota-rustaveli-boutique-hotel-standard-double-room-copy', 'Located in the heart of Tbilisi, Shota Rustaveli boutique hotel can boast a truly distinctive, unique style and concept. Modern, stylish and exquisite design gives this place a special touch of elegance and feeling of comfort and harmony. Wood-dominated interior and pastel colors creates laid-back atmosphere and makes you feel home away from home. The décor also includes some other raw natural materials like leather, iron and granite that gives an additional grace to the interior design. The hotel is just few steps away from Rustaveli Avenue, but guests can still feel very cozy and comfortable thanks to a quiet street across the avenue. Here you will find all the amenities and pleasures, that boutique hotel can offer. Gourmands will also be very happy here- the hotel’s restaurant, Melograno has one of the best cuisines in the city where you will enjoy various culinary delights. Refined style, enchanting food and highly personalized, top-quality service will make your stay here unforgettable.', 'Tbilisi', 'Georgia', '', 0, 'https://daydreamhub.com/wp-content/uploads/2024/11/relaxation.jpg', '["early_check-in","for_couple","transit_use"]', '["Elevator in Building","Gym","Laundry Service","Luggage Storage","Pool","Sauna","Wheelchair Accessible","Air Conditioner (Cooling)","Air Conditioner (Heating)","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Shampoo","Shower","TEL","Toothbrush","Towels","TV"]', 'Hotel', 1);
