INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (247, 'Pacific Inn / Deluxe King / Two Queen ROH', 'pacific-inn-deluxe-king-room', 'Welcome to The Pacific Inn. A delightful accommodation for two travelers seeking a memorable stay in Long Beach. Located near the beach, it’s perfect for exploring dining, shopping, and popular attractions like the Queen Mary. Enjoy spacious rooms with AC, private balconies, and free WiFi. Relax in the indoor pool and hot tub or on your balcony with a pool view. Start your day with the delicious breakfast takeaway service. They offer a convenient shuttle service. Friendly staff and pet-friendly. Walking distance to the pier and dining options. Comfort, convenience, and hospitality at The Pacific Inn.', 'Seal Beach', 'USA', '', 10, 'https://daydreamhub.com/wp-content/uploads/2024/10/565318512.jpg', '["early_check-in","for_work","transit_use"]', '["Elevator in Building","Laundry Service","Parking on Premises","Vending machine","Wheelchair Accessible","Air Conditioner (Cooling)","Air Conditioner (Heating)","Coffee maker","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Refrigerator","Shampoo","Shower","TEL","Toothbrush","Towels","TV"]', 'Hotel', 1);
