INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (257, 'AETAS lumpini Hotel / Deluxe Room', 'aetas-lumpini-hotel-deluxe-room', 'AETAS lumpini offers a prime location just a 3-minute walk from the MRT station, providing convenient access to Bangkok’s top attractions, including Terminal 21, Iconsiam, and the Temple of Dawn. The hotel features spacious rooms with modern amenities, including complimentary high-speed Wi-Fi, a free minibar, and elegant furnishings. Many rooms, such as our Junior Suite, boast stunning panoramic views of Bangkok’s skyline and Lumpini Park. Guests can start their day with a variety of delicious breakfast options and families can enjoy the dedicated Kid’s Club with engaging activities for children of all ages. The hotel also provides excellent leisure facilities, such as a pool and a fully-equipped fitness center. For business travelers, AETAS lumpini offers meeting rooms and an exclusive Executive Lounge with refreshments and evening cocktails. With concierge service and its proximity to lumpini Park, ideal for morning walks and relaxation, AETAS lumpini ensures a memorable stay for both business and leisure travelers.', 'Bangkok', 'Thailand', '', 0, 'https://daydreamhub.com/wp-content/uploads/2024/12/Deluxe-King-bed.jpg', '["for_couple","for_work","luxury"]', '["Bar / Restaurant","Currency Exchange","Elevator in Building","Fax","Gym","Laundry Service","Luggage Storage","Massage","Parking on Premises","Pool","Sauna","Wheelchair Accessible","Air Conditioner (Cooling)","Bathtub","Coffee maker","Desk/Workspace","Electric pot","Free Wi-Fi","Hair Dryer","Refrigerator","Shampoo","Shower","TEL","Toothbrush","Towels","TV"]', 'Hotel', 1);
