INSERT INTO hotels (id, name, slug, description, city, country, address, rating, thumbnail_url, categories, amenities, property_type, is_active) VALUES (258, 'Boutique Hotel Manufactura / Budget Double Room', 'boutique-hotel-manufactura-budget-double-room-3', 'Attractively located in the Avlabari district of Tbilisi, Boutique Hotel Manufactura is located a 18-minute walk from Freedom Square, 1.7 miles from Rustaveli Theater and 1.8 miles from Tbilisi Opera and Ballet Theater. This 4-star hotel offers a tour desk and luggage storage space. The property has a 24-hour front desk, airport transportation, room service and free WiFi.
